var now=new Date,hours=now.getHours(),minutes=now.getMinutes(),seconds=now.getSeconds(),year=now.getFullYear(),month=now.getMonth()+1,date=now.getDate();function f_n(n){return(n<10?"0":"")+n}function now_time(){return hours+":"+minutes+":"+seconds}function now_time_w0(){return f_n(hours)+":"+f_n(minutes)+":"+f_n(seconds)}function today(n){return year+n+month+n+date}function today_w0(n){return year+n+f_n(month)+n+f_n(date)}function week(){var n=now.getDay();return 0==n?n+7:n}function year_total_days(n){n&&(year=n);for(var t=0,e=1;e<13;e++)d=new Date(year,e,0),t+=d.getDate();return t}function month_total_days(n){return n&&(month=n),new Date(year,month,0).getDate()}function today_in_year(){return Math.ceil((now-new Date(year.toString()))/864e5)-1}
